DROP TABLE IF EXISTS "girl_photos";
CREATE TABLE girl_photos (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        girl_id INTEGER NOT NULL,
        filename TEXT NOT NULL,
        url TEXT NOT NULL,
        thumbnail_url TEXT,
        display_order INTEGER DEFAULT 0,
        is_primary BOOLEAN DEFAULT 0,
        width INTEGER,
        height INTEGER,
        file_size INTEGER,
        mime_type TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP, alt_text TEXT, alt_text_cs TEXT, alt_text_en TEXT, alt_text_de TEXT, alt_text_uk TEXT,
        FOREIGN KEY (girl_id) REFERENCES girls(id) ON DELETE CASCADE
      );

